pub enum AgentPermission {
    ReadOnly,
    ReadWrite { scopes: Vec<String> },
    Admin,
}
impl AgentPermission {
    pub fn can_write_scope(&self, scope_id: &str) -> bool {
        match self {
            Self::ReadOnly => false,
            Self::ReadWrite { scopes } => scopes.iter().any(|s| s == scope_id || s == "*"),
            Self::Admin => true,
        }
    }
}
